(72, 1, 'news_highlight', '{\"custom_id\":null,\"custom_class\":null,\"show_intro\":\"true\",\"intro_label\":{\"en\":\"MEDIA & ACTIVITIES\",\"id\":\"MEDIA & KEGIATAN\"},\"intro_title\":{\"en\":\"Keep up with what\'s happening at Linknet\",\"id\":\"Ikuti terus perkembangan terbaru di Linknet\"},\"featured_count\":1,\"grid_count\":3,\"order_by\":\"created_at\",\"order_direction\":\"desc\",\"show_category\":\"true\",\"show_date\":\"true\",\"enable_cta\":\"true\",\"cta_text\":null,\"cta_link\":null,\"bg_type\":\"color\",\"bg_color\":\"#ffffff\",\"bg_color_text\":\"#ffffff\",\"bg_image\":null,\"bg_position\":\"center\"}', 7, 1, '2025-10-08 06:19:11', '2025-12-19 09:43:20'),
(77, 1, 'business_tab', '{\"custom_id\":null,\"custom_class\":null,\"intro_label\":{\"en\":\"EXPLORE OUR BUSINESS\",\"id\":\"JELAJAHI BISNIS KAMI\"},\"intro_title\":{\"en\":\"Driving Better Lives Through Innovation\",\"id\":\"Meningkatkan Kualitas Hidup Melalui Inovasi\"},\"intro_description\":{\"en\":\"Linknet advances Indonesia\\u2019s digital transformation through innovative, reliable infrastructure.\",\"id\":\"Linknet memajukan transformasi digital Indonesia melalui infrastruktur yang inovatif dan andal.\"},\"tabs\":[{\"name\":\"EnterpriseCo\",\"id\":\"enterprise\",\"title\":\"Seamless Connectivity, Smart ICT Solutions, and Trusted Cybersecurity\",\"title_id\":\"Konektivitas Tanpa Batas, Solusi TIK Cerdas, dan Keamanan Siber yang Terpercaya\",\"description\":\"We provide reliable connectivity, technology, and cybersecurity solutions to support digital transformation. With over 3,300 customers, we deliver secure, high-performance internet and ICT services for large-scale enterprises while offering reliable connectivity for SMEs (Small Medium Enterprises) to help businesses grow in the digital era.\",\"description_id\":\"Kami menyediakan solusi konektivitas, teknologi, dan keamanan siber yang andal untuk mendukung transformasi digital. Dengan lebih dari 3.300 pelanggan, kami menghadirkan layanan internet dan TIK yang aman dan berkinerja tinggi untuk perusahaan berskala besar, sekaligus menawarkan konektivitas yang andal bagi UKM (Usaha Kecil dan Menengah) untuk membantu bisnis berkembang di era digital.\",\"background_image\":\"https:\\/\\/linknet.co.id\\/frontend\\/src\\/assets\\/bg\\/bg-enterprise.jpg\",\"logo_image\":\"https:\\/\\/linknet.co.id\\/frontend\\/src\\/assets\\/logos\\/logo-enterprise.svg\",\"bg_position\":\"right\",\"cta_text\":\"Learn More\",\"cta_text_id\":null,\"cta_link\":\"https:\\/\\/linknet.co.id\\/business\\/linknet-enterprise\"},{\"name\":\"FiberCo\",\"id\":\"fiberco\",\"title\":\"Your Solution for Nationwide Connectivity\",\"title_id\":\"Solusi Anda untuk Konektivitas Nasional\",\"description\":\"Linknet Fiber dedicated to delivering the ultimate internet experience with cutting-edge fiber optic technology that will connect Internet Service Providers (ISPs) to customers. Corinections via backbone and last mile networks allow ISPs to provide access to telecommunications services to customers\",\"description_id\":\"Linknet Fiber berkomitmen untuk menghadirkan pengalaman internet terbaik dengan teknologi serat optik mutakhir yang akan menghubungkan Penyedia Layanan Internet (ISP) kepada pelanggan. Koneksi melalui jaringan backbone dan last mile memungkinkan ISP menyediakan akses layanan telekomunikasi kepada pelanggan.\",\"background_image\":\"https:\\/\\/linknet.co.id\\/storage\\/files\\/1\\/assets\\/bg\\/ln-fiber-desktop.jpg\",\"logo_image\":\"https:\\/\\/linknet.co.id\\/frontend\\/src\\/assets\\/logos\\/logo-fiberco-white.png\",\"bg_position\":\"center\",\"cta_text\":\"Learn More\",\"cta_text_id\":null,\"cta_link\":\"https:\\/\\/linknet.co.id\\/business\\/linknet-fiber\"},{\"name\":\"MediaCo\",\"id\":\"mediaco\",\"title\":\"Your Gateway to Quality Content and Smarter Media\",\"title_id\":\"Gerbang Anda Menuju Konten Berkualitas dan Media yang Lebih Cerdas\",\"description\":\"Premium entertainment and media solutions that bring the best content directly to your home and business.\",\"description_id\":\"Solusi hiburan dan media premium yang menghadirkan konten terbaik langsung ke rumah dan bisnis Anda\",\"background_image\":\"https:\\/\\/www.linknet.co.id\\/storage\\/files\\/1\\/assets\\/bg\\/ln-media-desktop.jpg\",\"logo_image\":\"https:\\/\\/linknet.co.id\\/frontend\\/src\\/assets\\/logos\\/logo-mediaco.svg\",\"bg_position\":\"center\",\"cta_text\":\"Learn More\",\"cta_text_id\":null,\"cta_link\":\"https:\\/\\/linknet.co.id\\/business\\/linknet-media\"}],\"bg_type\":\"color\",\"bg_color\":\"#ffffff\",\"bg_color_text\":\"#ffffff\",\"bg_image\":null,\"bg_position\":\"center\"}', 4, 1, '2025-10-09 02:16:21', '2025-12-19 09:22:54'),
(78, 1, 'interactive_maps', '{\"business_units\":{\"BU1\":{\"label\":\"Area\",\"title\":\"Sumatera\",\"cities\":\"Medan, Batam, Palembang\"},\"BU2\":{\"label\":\"Area\",\"title\":\"Jakarta\",\"cities\":\"Jabo 1, Jabo 2, Jabo 3\"},\"BU3\":{\"label\":\"Area\",\"title\":\"West Java\",\"cities\":\"Bandung, Cirebon, Cikampek, Purwakarta, Subang, Sukabumi, Sumedang, Cianjur, Ciamis, Kuningan, Indramayu\"},\"BU4\":{\"label\":\"Area\",\"title\":\"Central Java\",\"cities\":\"Semarang, Yogyakarta, Solo, Tegal, Purwokerto, Pemalang, Mojokerto, Demak, Pati, Banyumas, Magelang, Purbalingga, Brebes, Cilacap\"},\"BU5\":{\"label\":\"Area\",\"title\":\"East Java & Bali\",\"cities\":\"Surabaya, Gresik, Sidoarjo, Malang, Kediri, Madiun, Bali, Bojonegoro, Tulungagung, Probolinggo, Ponorogo\"}},\"province_mapping\":{\"id-su\":\"BU1\",\"id-kr\":\"BU1\",\"id-sl\":\"BU1\",\"id-jk\":\"BU2\",\"id-jr\":\"BU3\",\"id-jt\":\"BU4\",\"id-yo\":\"BU4\",\"id-ji\":\"BU5\",\"id-ba\":\"BU5\"},\"custom_id\":\"coverage-section\",\"custom_class\":\"lnSection\",\"bg_section\":null,\"intro_label\":{\"en\":\"OPERATIONAL AREA\",\"id\":\"OPERATIONAL AREA\"},\"intro_title\":{\"en\":\"Linknet continues to expand its reach to serve more cities in Indonesia\",\"id\":\"Linknet terus memperluas jangkauannya untuk melayani lebih banyak kota di Indonesia.\"},\"intro_description\":{\"en\":\"Please click on one of the provinces\",\"id\":\"Silakan klik salah satu provinsi\"},\"map_hint\":{\"en\":\"Click on a province on the map\",\"id\":\"Klik salah satu provinsi pada peta\"},\"widget_title\":{\"en\":\"Detail Coverage\",\"id\":\"Cakupan Detil\"},\"widget_hint\":{\"en\":\"Click a province on the map to see details.\",\"id\":\"Klik provinsi pada peta untuk melihat detail.\"}}', 6, 1, '2025-10-09 19:26:47', '2025-12-19 09:25:29'),
(79, 3, 'sliders_hero', '{\"slides\": [{\"image\": \"/assets/bg/621.jpg\", \"title\": \"🇮🇩 Happy 80th Indonesia! From the Spirit of Independence, We Move Forward for the Future.\", \"pill_text\": \"🇮🇩 Our Mission\", \"button_link\": \"#\", \"button_text\": \"Get to Know Us\", \"description\": \"Together we move forward, building a future full of strength and prosperity.\", \"pill_visible\": false, \"button_visible\": false, \"image_position\": \"right\", \"indicator_label\": \"Indonesia Independence Day\"}, {\"image\": \"/assets/bg/hero-2.jpg\", \"title\": \"Improving Lives and Supporting Indonesia\'s Digital Growth\", \"pill_text\": \"🇮🇩 Our Mission\", \"button_link\": \"#\", \"button_text\": \"Get to Know Us\", \"description\": \"Linknet is dedicated to improving lives and supporting Indonesia\'s digital growth by delivering smart, reliable technology infrastructure through its three main business units\", \"pill_visible\": true, \"button_visible\": true, \"image_position\": \"center\", \"indicator_label\": \"Indonesia\'s Digital Growth\"}, {\"image\": \"/assets/bg/2806.jpg\", \"title\": \"Connecting 4 Million Homes, On Track to 8.4 Million by 2027\", \"pill_text\": \"Our Vision\", \"button_link\": \"#\", \"button_text\": \"Discover More\", \"description\": \"Link Net Continues to Expand Its Digital Footprint for a Closer, More Connected Future.\", \"pill_visible\": true, \"button_visible\": true, \"image_position\": \"center\", \"indicator_label\": \"4M Homepass\"}], \"autoplay\": true, \"custom_id\": \"hero-slider\", \"custom_class\": \"lnSection__hero\", \"autoplay_delay\": 5000, \"show_indicators\": true, \"show_navigation\": true, \"show_pagination\": true}', 1, 1, '2025-10-11 21:32:06', '2025-10-11 21:32:06'),
