(88, 4, 'information_list', '{\"custom_id\": \"\", \"bg_section\": \"\", \"intro_label\": \"MEDIA & ACTIVITIES\", \"intro_title\": \"Keep up with what\'s happening at Linknet\", \"custom_class\": \"\", \"info_sections\": [{\"title\": \"Our Vision\", \"content\": \"<p>The company was founded under the name PT Seruling Indah Permai in 1996 and then changed its name to PT Linknet Tbk in 2000 with business activities in the field of trading goods and services.</p><p>The Company operates HFC and FTTH cable systems with high technology and two-way broadband services.</p>\", \"documents\": [{\"url\": \"#\", \"date\": \"February 26, 2025\", \"icon\": \"src/assets/icons/pdf-circlesvg.svg\", \"title\": \"Anti-Bribery and Anti-Corruption Policy\", \"show_document\": true}, {\"url\": \"#\", \"date\": \"February 26, 2025\", \"icon\": \"src/assets/icons/pdf-circlesvg.svg\", \"title\": \"Gifts, Donations & Sponsorships Policy\", \"show_document\": true}, {\"url\": \"#\", \"date\": \"Mei 22, 2023\", \"icon\": \"src/assets/icons/pdf-circlesvg.svg\", \"title\": \"Anti-Bribery and Anti-Corruption Clauses\", \"show_document\": true}], \"show_section\": true, \"show_documents\": true, \"related_articles\": [{\"url\": \"#\", \"title\": \"Linknet Successfully Completed IPO On The Indonesia Stock Exchange (IDX)\", \"show_article\": true}, {\"url\": \"#\", \"title\": \"Rebranding of OTT Service From \\\"First Media Live\\\" To \\\"First Media Go\\\"\", \"show_article\": true}], \"show_related_articles\": true}, {\"title\": \"About Linknet\", \"content\": \"<p>Linknet is dedicated to improving lives and supporting Indonesia\'s digital growth by delivering smart, reliable technology infrastructure through its three main business units.</p>\", \"documents\": [], \"show_section\": true, \"show_documents\": false, \"related_articles\": [], \"show_related_articles\": false}], \"intro_description\": \"Stay Update\", \"show_intro_section\": true}', 5, 1, '2025-10-12 05:10:38', '2025-10-12 09:39:21'),
(89, 4, 'join_first_squad', '{\"slides\": [{\"image\": \"frontend/src/assets/photos/thumb/fs.png\", \"title\": \"First Squad\", \"cta_link\": \"#first-squad\", \"cta_text\": \"Join as a First Squad\", \"headline\": \"Are You Ready to Become First Squad At Linknet?\", \"subtitle\": \"Become First Squad as\", \"description\": \"At Linknet, First Squad will contribute in providing the best experience for all of our customers. Let\'s join a company that sees potential and supports the development of every individual in it.\"}, {\"image\": \"frontend/src/assets/photos/thumb/mt.png\", \"title\": \"Management<br/>Trainee\", \"cta_link\": \"#management-trainee\", \"cta_text\": \"Join as a Management Trainee\", \"headline\": \"Management Trainee Program at Linknet\", \"subtitle\": \"Become First Squad as\", \"description\": \"Every year, Linknet recruits the best graduates through the Management Trainee (MT) program. MT will be equipped with a comprehensive program and receive the best development program to prepare MT as future leader at PT Link Net Tbk.\"}, {\"image\": \"frontend/src/assets/photos/thumb/intern.png\", \"title\": \"First Squad Intern\", \"cta_link\": \"#first-squad-intern\", \"cta_text\": \"See Internship Openings\", \"headline\": \"Get Ready to Be First Squad Intern, Now!\", \"subtitle\": \"Become First Squad as\", \"description\": \"Start your career journey as a First Squad Intern at Linknet. By becoming a First Squad Intern, you will have the opportunity to learn, contribute and develop your knowledge professionally as a preparation for your career journey ahead.\"}], \"custom_id\": \"\", \"bg_section\": \"var(--bg-light-2)\", \"intro_label\": \"JOIN US AS FIRST SQUAD\", \"intro_title\": \"Continuous Growth and Stability: A Grateful Journey at Linknet\", \"custom_class\": \"lnSection__JoinFirstSquad\"}', 6, 1, '2025-10-12 05:19:39', '2025-10-12 09:39:21'),
