(91, 4, 'sliders_hero', '{\"slides\": [{\"image\": \"src/assets/bg/621.jpg\", \"title\": \"🇮🇩 Happy 80th Indonesia! From the Spirit of Independence, We Move Forward for the Future.\", \"pill_text\": \"🇮🇩 Our Mission\", \"button_link\": \"#\", \"button_text\": \"Get to Know Us\", \"description\": \"Together we move forward, building a future full of strength and prosperity.\", \"pill_visible\": false, \"button_visible\": false, \"image_position\": \"right\", \"indicator_label\": \"Indonesia Independence Day\"}, {\"image\": \"src/assets/bg/hero-2.jpg\", \"title\": \"Improving Lives and Supporting Indonesia\'s Digital Growth\", \"pill_text\": \"🇮🇩 Our Mission\", \"button_link\": \"#\", \"button_text\": \"Get to Know Us\", \"description\": \"Linknet is dedicated to improving lives and supporting Indonesia\'s digital growth by delivering smart, reliable technology infrastructure through its three main business units\", \"pill_visible\": true, \"button_visible\": true, \"image_position\": \"center\", \"indicator_label\": \"Indonesia\'s Digital Growth\"}, {\"image\": \"src/assets/bg/2806.jpg\", \"title\": \"Connecting 4 Million Homes, On Track to 8.4 Million by 2027\", \"pill_text\": \"Our Vision\", \"button_link\": \"#\", \"button_text\": \"Discover More\", \"description\": \"Link Net Continues to Expand Its Digital Footprint for a Closer, More Connected Future.\", \"pill_visible\": true, \"button_visible\": true, \"image_position\": \"center\", \"indicator_label\": \"4M Homepass\"}, {\"image\": \"src/assets/bg/top-view-business-people-writing-mind-map-while-brainstorm-idea-convocation.jpg\", \"title\": \"Let\'s Join Management Trainee Generation 6\", \"pill_text\": \"🤝 We\'re Hiring\", \"button_link\": \"#\", \"button_text\": \"Apply Now\", \"description\": \"Link Net Management Trainee Program is a comprehensive program that enables the organization to develop and grow fit capable young leaders for a managerial role in the company.\", \"pill_visible\": true, \"button_vi