(105, 5, 'highlighting_real_initiatives', '{\"cta_url\": \"#\", \"cta_text\": \"View All CSR Program\", \"custom_id\": \"\", \"bg_section\": \"\", \"initiatives\": [{\"logo\": \"src/assets/img/soc-logo-1.png\", \"title\": \"Centratama Group and Linknet to Enhance Broadband Connectivity Across Indonesia\", \"cta_url\": \"#\", \"cta_text\": \"See Detail\", \"thumbnail\": \"src/assets/img/soc-1.png\", \"description\": \"Through tree planting as part of its CSR activities, PT Link Net Tbk not only reduces its carbon footprint and generates positive effects on the environment but also provides long-term benefits in preserving biodiversity and improving air quality.\"}, {\"logo\": \"src/assets/img/soc-logo-2.png\", \"title\": \"Digital Literacy Program for Remote Communities\", \"cta_url\": \"#\", \"cta_text\": \"See Detail\", \"thumbnail\": \"src/assets/img/soc-2.png\", \"description\": \"Empowering remote communities through comprehensive digital literacy programs that provide essential skills for the modern digital economy.\"}, {\"logo\": \"src/assets/img/soc-logo-3.png\", \"title\": \"Environmental Conservation Initiative\", \"cta_url\": \"#\", \"cta_text\": \"See Detail\", \"thumbnail\": \"src/assets/img/soc-3.png\", \"description\": \"Supporting environmental conservation through sustainable practices and community engagement programs that protect our natural resources.\"}], \"intro_label\": \"STORIES OF CHANGE\", \"intro_title\": \"Highlighting Real Initiatives\", \"custom_class\": \"lnSection__highlightingRealInitiatives bg-gradient-yellow\", \"community_text\": \"We also work with community organizations,\", \"community_logos\": [{\"image\": \"src/assets/img/org-1.png\", \"alt_text\": \"Partner Organization 1\"}, {\"image\": \"src/assets/img/org-2.png\", \"alt_text\": \"Partner Organization 2\"}, {\"image\": \"src/assets/img/org-3.png\", \"alt_text\": \"Partner Organization 3\"}, {\"image\": \"src/assets/img/org-4.png\", \"alt_text\": \"Partner Organization 4\"}, {\"image\": \"src/assets/img/org-5.png\", \"alt_text\": \"Partner Organization 5\"}, {\"image\": \"src/assets/img/org-6.png\", \"alt_text\": \"Partner Organization 6\"}], \"show_cta_section\": true, \"intro_description\": \"From digital literacy to environmental stewardship, that bring positive impact to communities.\", \"show_intro_section\": true, \"show_slider_section\": true, \"show_community_section\": true}', 6, 1, '2025-10-12 10:03:15', '2025-10-12 12:01:40'),
