(107, 5, 'information_list', '{\"custom_id\": \"\", \"bg_section\": \"\", \"intro_label\": \"MEDIA & ACTIVITIES\", \"intro_title\": \"Keep up with what\'s happening at Linknet\", \"custom_class\": \"\", \"info_sections\": [{\"title\": \"Our Vision\", \"content\": \"<p>The company was founded under the name PT Seruling Indah Permai in 1996 and then changed its name to PT Linknet Tbk in 2000 with business activities in the field of trading goods and services.</p><p>The Company operates HFC and FTTH cable systems with high technology and two-way broadband services.</p>\", \"documents\": [{\"url\": \"#\", \"date\": \"February 26, 2025\", \"icon\": \"src/assets/icons/pdf-circlesvg.svg\", \"title\": \"Anti-Bribery and Anti-Corruption Policy\", \"show_document\": true}, {\"url\": \"#\", \"date\": \"February 26, 2025\", \"icon\": \"src/assets/icons/pdf-circlesvg.svg\", \"title\": \"Gifts, Donations & Sponsorships Policy\", \"show_document\": true}, {\"url\": \"#\", \"date\": \"Mei 22, 2023\", \"icon\": \"src/assets/icons/pdf-circlesvg.svg\", \"title\": \"Anti-Bribery and Anti-Corruption Clauses\", \"show_document\": true}], \"show_section\": true, \"show_documents\": true, \"related_articles\": [{\"url\": \"#\", \"title\": \"Linknet Successfully Completed IPO On The Indonesia Stock Exchange (IDX)\", \"show_article\": true}, {\"url\": \"#\", \"title\": \"Rebranding of OTT Service From \\\"First Media Live\\\" To \\\"First Media Go\\\"\", \"show_article\": true}], \"show_related_articles\": true}, {\"title\": \"About Linknet\", \"content\": \"<p>Linknet is dedicated to improving lives and supporting Indonesia\'s digital growth by delivering smart, reliable technology infrastructure through its three main business units.</p>\", \"documents\": [], \"show_section\": true, \"show_documents\": false, \"related_articles\": [], \"show_related_articles\": false}], \"intro_description\": \"Stay Update\", \"show_intro_section\": true}', 8, 1, '2025-10-12 10:03:23', '2025-10-12 12:01:40'),
