(112, 1, 'usp_grid', '{\"custom_id\":null,\"custom_class\":null,\"show_intro\":\"true\",\"intro_label\":{\"en\":\"OUR PURPOSE\",\"id\":\"TUJUAN KAMI\"},\"intro_title\":{\"en\":\"We LINK the nation for better lives\",\"id\":\"Kami menghubungkan bangsa untuk kehidupan yang lebih baik\"},\"intro_description\":{\"en\":\"Through Hybrid Fiber Coaxial (HFC) and Fiber To The Home (FTTH) networks, Linknet provides reliable internet, multimedia, and business solutions to over 4 million homepasses in 70+ cities\",\"id\":\"Melalui jaringan Hybrid Fiber Coaxial (HFC) dan Fiber To The Home (FTTH), Linknet menyediakan solusi internet, multimedia, dan bisnis yang andal kepada lebih dari 4 juta pelanggan rumahan di 70+ kota.\"},\"show_action\":\"true\",\"action_text\":{\"en\":\"Get to Know Us\",\"id\":\"Kenali Kami\"},\"action_url\":\"\\/about\\/corporate-overview\",\"grid_columns\":\"4\",\"spacing\":\"g-4\",\"items\":[{\"icon\":\"https:\\/\\/linknet.co.id\\/\\/storage\\/files\\/1\\/usp\\/icon-homepass.svg\",\"title\":\"4M+ Homepasses\",\"title_id\":\"4M+ Homepasses\",\"label\":null,\"label_id\":null,\"description\":\"Spread across more than 47 major cities in Indonesia\",\"description_id\":\"Menjangkau lebih dari 47 kota besar di seluruh Indonesia\",\"text_position\":\"left\"},{\"icon\":\"https:\\/\\/linknet.co.id\\/\\/storage\\/files\\/1\\/usp\\/icon-business.svg\",\"title\":\"3 Pillars of Business\",\"title_id\":\"3 Pilar Bisnis\",\"label\":null,\"label_id\":null,\"description\":\"FiberCo, EnterpriseCo, and MediaCo for complete solutions\",\"description_id\":\"FiberCo, EnterpriseCo, dan MediaCo untuk solusi yang lengkap\",\"text_position\":\"left\"}],\"bg_type\":\"image\",\"bg_color\":\"#ffffff\",\"bg_color_text\":\"#ffffff\",\"bg_image\":\"https:\\/\\/www.linknet.co.id\\/storage\\/files\\/1\\/assets\\/bg\\/bg-usp-home.jpg\",\"bg_position\":\"bottom right\"}', 2, 1, '2025-10-12 19:30:11', '2026-01-21 04:35:49'),
(113, 1, 'tabs_with_card', '{\"custom_id\":null,\"custom_class\":\"lnSection__reports\",\"show_intro\":\"true\",\"intro_label\":{\"en\":\"REPORT & ANNOUNCEMENT\",\"id\":\"LAPORAN & PENGUMUMAN\"},\"intro_title\":{\"en\":\"Performance Transparency & Corporate Announcements\",\"id\":\"Transparansi Kinerja & Pengumuman Korporat\"},\"intro_description\":{\"en\":\"Discover our latest reports and explore the results we have delivered to our shareholders\",\"id\":\"Temukan laporan terbaru kami dan jelajahi hasil yang telah kami berikan kepada para pemegang saham kami.\"},\"show_action\":\"false\",\"action_url\":null,\"tabs\":[{\"label\":\"Report\",\"label_id\":null,\"id\":\"report\",\"cards\":[{\"title\":\"Annual Reports\",\"title_id\":\"Laporan Tahunan\",\"description\":\"Discover our annual journey of growth, strategies, and achievements.\",\"description_id\":\"Temukan perjalanan pertumbuhan, strategi, dan pencapaian kami setiap tahunnya.\",\"icon\":\"pdf-circlesvg.svg\",\"button_text\":\"View More\",\"button_text_id\":\"Lihat Selengkapnya\",\"button_url\":\"https:\\/\\/linknet.co.id\\/investor\\/annual-report\"},{\"title\":\"Financial Statement\",\"title_id\":\"Laporan Keuangan\",\"description\":\"View our financial transparency, fostering trust and new opportunities.\",\"description_id\":\"Lihat transparansi keuangan kami yang mendorong kepercayaan dan peluang baru.\",\"icon\":\"pdf-circlesvg.svg\",\"button_text\":\"View More\",\"button_text_id\":\"Lihat Selengkapnya\",\"button_url\":\"https:\\/\\/linknet.co.id\\/investor\\/financial-statement\"},{\"title\":\"Sustainability Report\",\"title_id\":\"Laporan Keberlanjutan\",\"description\":\"Follow our commitment to building a sustainable future for businesses and society.\",\"description_id\":\"Ikuti komitmen kami membangun masa depan berkelanjutan bagi bisnis dan masyarakat.\",\"icon\":\"pdf-circlesvg.svg\",\"button_text\":\"View More\",\"button_text_id\":\"Lihat Selengkapnya\",\"button_url\":\"https:\\/\\/linknet.co.id\