(114, 7, 'hero_section', '{\"custom_id\":\"lnSection__hero\",\"custom_class\":\"lnSection__hero\",\"aria_label\":\"Our Vision\",\"background_image\":\"https:\\/\\/linknet.co.id\\/storage\\/files\\/1\\/herosliders\\/top-view-business-people-writing-mind-map-while-brainstorm-idea-convocation.jpg\",\"background_image_mobile\":null,\"bg_position_desktop\":\"center\",\"bg_position_mobile\":\"center\",\"size_hero\":\"lnHero__small\",\"theme\":\"dark\",\"gradient_visible\":\"true\",\"minilogo_visible\":\"false\",\"minilogo_image\":null,\"pill_visible\":\"true\",\"subtitle\":\"Life at Linknet\",\"subtitle_id\":null,\"title\":\"Let\'s Discover the Possibilities Together!\",\"title_id\":\"Ayo Jelajahi Segala Kemungkinan Bersama!\",\"description\":null,\"description_id\":null,\"description_width\":\"w-75\",\"button_visible\":\"true\",\"button_text\":\"Discover Our Career\",\"button_text_id\":\"Temukan Peluang Karier\",\"button_link\":\"\\/life-at-linknet\\/careers\",\"button_icon\":\"arrow-top-right.svg\",\"button_size\":\"btn-lg\"}', 1, 1, '2025-10-12 21:47:38', '2025-11-29 01:04:19'),
(115, 7, 'about_with_marquee', '{\"custom_id\":null,\"custom_class\":\"lnSection__polaroidMarquee\",\"show_intro\":\"true\",\"intro_label\":\"LIFE AT LINKNET\",\"intro_label_id\":null,\"intro_title\":\"At Linknet, we believe that First Squad has an important role in giving the best contribution in the organization.\",\"intro_title_id\":\"Di Linknet, kami percaya bahwa First Squad memiliki peran penting dalam memberikan kontribusi terbaik bagi organisasi.\",\"intro_description\":\"As First Squad, we collaborate to achieve common goals and have a positive impact on the company. So, ready to join us as First Squad?\",\"intro_description_id\":\"Sebagai First Squad, kami bekerja sama untuk mencapai tujuan bersama dan memberikan dampak positif bagi perusahaan. Jadi, siap bergabung dengan kami sebagai First Squad?\",\"show_intro_actions\":\"false\",\"intro_button_text\":\"Get to Know Us\",\"intro_button_text_id\":\"Lihat Selengkapnya\",\"intro_button_link\":\"#\",\"photos\":[{\"image\":\"src\\/assets\\/photos\\/polaroid\\/1.jpg\",\"alt_text\":\"Team moment 1\"},{\"image\":\"src\\/assets\\/photos\\/polaroid\\/2.jpg\",\"alt_text\":\"Team moment 2\"},{\"image\":\"src\\/assets\\/photos\\/polaroid\\/3.jpg\",\"alt_text\":\"Team moment 3\"},{\"image\":\"src\\/assets\\/photos\\/polaroid\\/4.jpg\",\"alt_text\":\"Team moment 4\"},{\"image\":\"src\\/assets\\/photos\\/polaroid\\/5.jpg\",\"alt_text\":\"Team moment 5\"}],\"marquee_speed\":0,\"marquee_direction\":\"left\",\"bg_type\":\"color\",\"bg_color\":\"#ffffff\",\"bg_color_text\":\"#ffffff\",\"bg_image\":null,\"bg_position\":\"center\"}', 2, 1, '2025-10-12 21:49:24', '2025-11-29 01:05:37'),
(116, 7, 'join_first_squad', '{\"custom_id\":null,\"custom_class\":\"lnSection__JoinFirstSquad\",\"intro_label\":\"JOIN US AS FIRST SQUAD\",\"intro_label_id\":null,\"intro_title\":\"Continuous Growth and Stability: A Grateful Journey at Linknet\",\"intro_title_id\":\"Pertumbuhan dan Stabilitas Berkelanjutan: Perjalanan Penuh Rasa Syukur di Linknet\",\"slides\":[{\"image\":\"frontend\\/src\\/assets\\/photos\\/thumb\\/fs.png\",\"subtitle\":\"Become First Squad as\",\"subtitle_id\":null,\"title\":\"First Squad\",\"title_id\":null,\"headline\":\"Are You Ready to Become First Squad At Linknet?\",\"headline_id\":null,\"description\":\"At Linknet, First Squad will contribute in providing the best experience for all of our customers. Let\'s join a company that sees potential and supports the development of every individual in it.\",\"description_id\":\"Di Linknet, First Squad akan berkontribusi dalam memberikan pengalaman terbaik bagi seluruh pelanggan kami. Bergabunglah dengan perusahaan yang melihat potensi dan mendukung pengembangan setiap individu di dalamnya.\",\"cta_text\":\"Join as a First Squad\",\"cta_text_id\":null,\"cta_link\":\"#first-squad\"},{\"image\":\"frontend\\/src\\/assets\\/photos\\/thumb\\/mt.png\",\"subtitle\":\"Become First Squad as\",\"subtitle_id\":null,\"title\":\"Management<br\\/>Trainee\",\"title_id\":null,\"headline\":\"Management Trainee Program at Linknet\",\"headline_id\":null,\"description\":\"Every year, Linknet recruits the best graduates through the Management Trainee (MT) program. MT will be equipped with a comprehensive program and receive the best development program to prepare MT as future leader at PT Link Net Tbk.\",\"description_id\":\"Setiap tahun, Linknet merekrut lulusan terbaik melalui program Management Trainee (MT). Para MT akan dibekali dengan program yang komprehensif serta menerima program pengembangan terbaik untuk mempersiapkan mereka sebagai pemimpin masa depan di PT Link Net Tbk.\",\"cta_text\":\"Join as a Management Trainee\",\"cta_text_id\":null,\"cta_link\":\"#management-trainee\"},{\"image\":\"frontend\\/src\\/assets\\/photos\\/thumb\\/intern.png\",\"subtitle\":\"Become First Squad as\",\"subtitle_id\":null,\"title\":\"First Squad Intern\",\"title_id\":null,\"headline\":\"Get Ready to Be First Squad Intern, Now!\",\"headline_id\":null,\"description\":\"Start your career journey as a First Squad Intern at Linknet. By becoming a First Squad Intern, you will have the opportunity to learn, contribute and develop your knowledge professionally as a preparation for your career journey ahead.\",\"description_id\":\"Mulailah perjalanan kariermu sebagai First Squad Intern di Linknet. Dengan menjadi First Squad Intern, kamu akan memiliki kesempatan untuk belajar, berkontribusi, dan mengembangkan pengetahuan secara profesional sebagai persiapan untuk perjalanan kariermu ke depan.\",\"cta_text\":\"See Internship Openings\",\"cta_text_id\":null,\"cta_link\":\"#first-squad-intern\"}],\"bg_type\":\"color\",\"bg_color\":\"#ffffff\",\"bg_color_text\":\"#ffffff\",\"bg_image\":null,\"bg_position\":\"center\"}', 3, 1, '2025-10-12 23:43:47', '2025-11-29 01:07:52'),
(117, 7, 'career_highlight', '{\"intro_label\":\"LET\'S DISCOVER POSSIBILITIES TOGETHER\",\"intro_label_id\":null,\"intro_title\":\"Let\'s join Linknet and become First Squad\",\"intro_title_id\":null,\"show_discover_more_btn\":true,\"discover_more_btn_text\":\"Discover More\",\"discover_more_btn_text_id\":\"Lihat Selengkapnya\",\"discover_more_btn_link\":\"https:\\/\\/linknet.co.id\\/life-at-linknet\\/careers\"}', 4, 1, '2025-10-13 00:25:19', '2025-11-29 01:08:18'),
