(125, 11, 'hero_section', '{\"custom_id\":\"lnSection__hero\",\"custom_class\":\"lnSection__hero\",\"aria_label\":\"Our Vision\",\"background_image\":\"https:\\/\\/linknet.co.id\\/storage\\/files\\/1\\/sustainbg.png\",\"background_image_mobile\":null,\"bg_position_desktop\":\"center\",\"bg_position_mobile\":\"center\",\"size_hero\":\"lnHero__medium\",\"theme\":\"dark\",\"gradient_visible\":\"true\",\"minilogo_visible\":\"false\",\"minilogo_image\":null,\"pill_visible\":\"true\",\"subtitle\":{\"en\":\"Sustainability\"},\"title\":{\"en\":\"At Linknet, we embed sustainability into everything we do\"},\"description\":{\"en\":\"Creating inclusive digital access, reducing our environmental footprint, and building lasting trust with stakeholders.\"},\"description_width\":\"w-75\",\"button_visible\":\"true\",\"button_text\":{\"en\":\"Explore Our ESG Journey\"},\"button_link\":\"#SustainabilityIDGoTo\",\"button_icon\":\"arrow-top-right.svg\",\"button_size\":\"btn-lg\"}', 1, 1, '2025-10-13 23:32:29', '2025-12-22 07:13:08'),
(126, 11, 'usp_grid', '{\"custom_id\":\"SustainabilityIDGoTo\",\"custom_class\":null,\"show_intro\":\"true\",\"intro_label\":{\"en\":\"KEY PILLARS \\/ FOCUS AREA\",\"id\":\"PILAR UTAMA \\/ AREA FOKUS\"},\"intro_title\":{\"en\":\"Our Key Pillars of Sustainability\",\"id\":\"Pilar-Pilar Utama Keberlanjutan Kami\"},\"intro_description\":{\"en\":\"Three focus areas guiding our initiatives: Inclusion for people, resilience for the planet, and trust for long-term growth.\",\"id\":\"Tiga area fokus yang memandu inisiatif kami: Inklusi bagi masyarakat, ketahanan bagi planet ini, dan kepercayaan untuk pertumbuhan jangka panjang.\"},\"show_action\":\"false\",\"action_url\":null,\"grid_columns\":\"3\",\"spacing\":\"g-4\",\"items\":[{\"icon\":\"https:\\/\\/linknet.co.id\\/storage\\/files\\/1\\/uspgrid\\/image 34.png\",\"title\":\"Link for Inclusion\",\"title_id\":\"Link untuk Inklusi\",\"label\":null,\"label_id\":null,\"description\":\"Digital Inclusion | Equal Access | Stronger Diversity\",\"description_id\":\"Inklusi Digital | Akses Setara | Keberagaman yang Lebih Kuat\",\"text_position\":\"left\"},{\"icon\":\"https:\\/\\/linknet.co.id\\/storage\\/files\\/1\\/uspgrid\\/fi_1598431.svg\",\"title\":\"Link for the Living Planet\",\"title_id\":\"Link untuk Planet yang Berkelanjutan\",\"label\":null,\"label_id\":null,\"description\":\"Climate Resilience | Green Innovation | Lower Footprint\",\"description_id\":\"Resiliensi Iklim | Inovasi Ramah Lingkungan | Jejak Emisi yang Lebih Rendah\",\"text_position\":\"left\"},{\"icon\":\"https:\\/\\/linknet.co.id\\/storage\\/files\\/1\\/uspgrid\\/shield.svg\",\"title\":\"Link for Lasting Trust\",\"title_id\":\"Link untuk Kepercayaan yang Berkelanjutan\",\"label\":null,\"label_id\":null,\"description\":\"Governance & Compliance | Responsible Growth | Accountability\",\"description_id\":\"Governansi & Kepatuhan | Pertumbuhan Berkelanjutan yang Bertanggung Jawab | Akuntabilitas\",\"text_position\":\"left\"}],\"bg_type\":\"color\",\"bg_color\":\"#ffffff\",\"bg_color_text\":\"#ffffff\",\"bg_image\":null,\"bg_position\":\"center\"}', 2, 1, '2025-10-13 23:37:47', '2025-12-22 07:12:55'),
(127, 11, 'key_highlight', '{\"custom_id\":null,\"custom_class\":\"lnSection__keyHighlightWithImage\",\"intro_label\":{\"en\":\"KEY HIGHLIGHT\",\"id\":\"SOROTAN UTAMA\"},\"intro_title\":{\"en\":\"Our Impact in Numbers\",\"id\":\"Dampak Kami dalam Angka\"},\"intro_description\":{\"en\":\"Measurable achievements that reflect our progress. From digital access and workforce diversity to environmental action.\",\"id\":\"Pencapaian terukur yang mencerminkan kemajuan kami. Dari akses digital dan keragaman tenaga kerja hingga aksi lingkungan.\"},\"slides\":[{\"image\":\"src\\/assets\\/bg\\/2806.jpg\",\"value\":{\"en\":\"4,07 Million\",\"id\":\"4.07 Juta\"},\"delta\":{\"en\":\"(+14,6% YoY)\"},\"caption\":{\"en\":\"Homes connected through open access\",\"id\":\"Rumah terkoneksi melalui akses terbuka\"}},{\"image\":\"src\\/assets\\/photos\\/young-woman-using-phone-while-sitting-table.jpg\",\"value\":{\"en\":\"29,1%\"},\"delta\":{\"en\":\"(+4,9% YoY)\"},\"caption\":{\"en\":\"Women in Workforce \\/ Leadership\",\"id\":\"Perempuan dalam Dunia Kerja \\/ Kepemimpinan\"}},{\"image\":\"src\\/assets\\/photos\\/view-green-forest-trees-with-co2.jpg\",\"value\":{\"en\":\"\\u00b1 23.162 tCO\\u2082e\"},\"caption\":{\"en\":\"Potential Carbon Sequestration\",\"id\":\"Potensi Penyerapan Karbon\"}},{\"image\":\"src\\/assets\\/photos\\/planting-trees-as-part-reforestation-process.jpg\",\"value\":{\"en\":\"New Program\",\"id\":\"Program Baru\"},\"caption\":{\"en\":\"Trees planted (\\u201cNew Homepass, New Tree\\u201d)\",\"id\":\"Penanaman Pohon (\\u2018Setiap Homepass Baru, Satu Pohon Baru\\u2019)\"}},{\"image\":\"src\\/assets\\/photos\\/20250227_095744.jpg\",\"value\":{\"en\":\"2,321\"},\"caption\":{\"en\":\"No. of customers\\/communities reached through ISPs and Enterprise\",\"id\":\"Jumlah pelanggan\\/komunitas yang dijangkau melalui ISP dan Enterprise\"}},{\"image\":\"src\\/assets\\/photos\\/colleagues-working-together-high-angle.jpg\",\"value\":{\"en\":\"6,764 Hours\",\"id\":\"6.764 Jam\"},