(128, 11, 'card_with_highlight_summary', '{\"custom_id\":null,\"custom_class\":\"lnSection__reports\",\"bg_type\":\"color\",\"bg_color\":\"#ffffff\",\"bg_color_text\":\"#ffffff\",\"bg_image\":null,\"bg_position\":\"center\",\"show_intro_section\":\"true\",\"intro_label\":{\"en\":\"SUSTAINABILITY REPORTS & POLICY\",\"id\":\"LAPORAN & KEBIJAKAN KEBERLANJUTAN\"},\"intro_title\":{\"en\":\"Transparency & Accountability\",\"id\":\"Transparansi & Akuntabilitas\"},\"intro_description\":{\"en\":\"Explore our latest Sustainability Reports, ESG policies, and alignment with international frameworks to ensure responsible growth.\",\"id\":\"Jelajahi Laporan Keberlanjutan terbaru kami, kebijakan ESG, dan keselarasan dengan kerangka kerja internasional untuk memastikan pertumbuhan yang bertanggung jawab.\"},\"show_cards_section\":\"true\",\"cards\":[{\"title\":{\"en\":\"Annual Reports\",\"id\":\"Laporan Tahunan\"},\"description\":{\"en\":\"Discover our growth journey, strategies, and achievements each year\",\"id\":\"Temukan perjalanan pertumbuhan, strategi, dan pencapaian kami setiap tahunnya\"},\"icon\":\"frontend\\/src\\/assets\\/icons\\/pdf-circlesvg.svg\",\"button_text\":{\"en\":\"View More\",\"id\":\"Lihat Selengkapnya\"},\"button_link\":\"\\/investor\\/annual-report\"},{\"title\":{\"en\":\"Financial Statement\",\"id\":\"Laporan Keuangan\"},\"description\":{\"en\":\"See our financial transparency that fosters trust and new opportunities\",\"id\":\"Lihat transparansi keuangan kami yang mendorong kepercayaan dan peluang baru\"},\"icon\":\"frontend\\/src\\/assets\\/icons\\/pdf-circlesvg.svg\",\"button_text\":{\"en\":\"View More\",\"id\":\"Lihat Selengkapnya\"},\"button_link\":\"\\/investor\\/financial-statement\"},{\"title\":{\"en\":\"Sustainability Report\",\"id\":\"Laporan Keberlanjutan\"},\"description\":{\"en\":\"Follow our commitment to building a sustainable future for business and society\",\"id\":\"Ikuti komitmen kami membangun masa depan berkelanjutan bagi bisnis dan masyarakat\"},\"icon\":\"frontend\\/src\\/assets\\/icons\\/pdf-circlesvg.svg\",\"button_text\":{\"en\":\"View More\",\"id\":\"Lihat Selengkapnya\"},\"button_link\":\"\\/investor\\/sustainable-report\"}],\"show_highlight_section\":\"false\",\"highlight_thumbnail\":\"frontend\\/src\\/assets\\/img\\/LINK AR2024 Rev_page-0001.jpg\",\"highlight_title\":{\"en\":\"Highlight Report Summary\"},\"highlight_year\":\"2024\",\"highlight_metrics\":[{\"value\":\"4.07M\",\"delta\":\"(+14.65% YoY)\",\"label\":{\"en\":\"Homes Connected (Open Access\",\"id\":\"Rumah Terkoneksi (Akses Terbuka)\"}},{\"value\":\"32,421.94 ton CO\\u2082e\",\"delta\":\"(\\u20137.21%)\",\"label\":{\"en\":\"GHG Emissions (Lower is Better)\",\"id\":\"Emisi Gas Rumah Kaca (Semakin Rendah Semakin Baik)\"}},{\"value\":\"29.07%\",\"delta\":\"(+4.91%)\",\"label\":{\"en\":\"Women in Workforce\",\"id\":\"Perempuan dalam Tenaga Kerja\"}}],\"highlight_button_text\":{\"en\":\"Download Report\"},\"highlight_button_link\":\"#\"}', 4, 1, '2025-10-13 23:52:36', '2025-12-12 07:36:57'),
(129, 11, 'highlighting_real_initiatives', '{\"custom_id\":null,\"custom_class\":\"lnSection__highlightingRealInitiatives bg-gradient-yellow\",\"bg_type\":\"color\",\"bg_color\":\"#ffffff\",\"bg_color_text\":\"#ffffff\",\"bg_image\":null,\"bg_position\":\"center\",\"show_intro_section\":\"true\",\"intro_label\":{\"en\":\"STORIES OF CHANGE\",\"id\":\"KISAH-KISAH PERUBAHAN\"},\"intro_title\":{\"en\":\"Highlighting Real Initiatives\",\"id\":\"Menyoroti Inisiatif Nyata\"},\"intro_description\":{\"en\":\"From digital literacy to environmental stewardship, that bring positive impact to communities.\",\"id\":\"Mulai dari literasi digital hingga pelestarian lingkungan, yang membawa dampak positif bagi masyarakat.\"},\"show_slider_section\":\"true\",\"initiatives\":[{\"logo\":\"frontend\\/src\\/assets\\/img\\/soc-logo-1.png\",\"thumbnail\":\"frontend\\/src\\/assets\\/img\\/soc-1.png\",\"title\":{\"en\":\"Committed to Environmental Sustainability, PT Link Net Tbk Plants 3,000 Mangrove Trees in North Jakarta\",\"id\":\"Komitmen Terhadap Keberlanjutan Lingkungan, PT Link Net Tbk tanam 3.000 Pohon Bakau di Jakarta Utara\"},\"description\":{\"en\":\"PT Link Net Tbk planted 3,000 mangrove trees in North Jakarta.\",\"id\":\"PT Link Net Tbk lakukan penanaman 3.000 pohon bakau di Jakarta Utara\"},\"cta_text\":{\"en\":\"See Detail\"},\"cta_url\":\"https:\\/\\/linknet.co.id\\/news\\/csr-linknet-tanam-pohonbakau-3000\"},{\"logo\":\"frontend\\/src\\/assets\\/img\\/soc-logo-2.png\",\"thumbnail\":\"https:\\/\\/linknet.co.id\\/storage\\/files\\/images\\/media_activities\\/csr\\/csr-peduli-2.jpg\",\"title\":{\"en\":\"Multivitamin & Personal Protective Equipment Donations\",\"id\":\"Multivitamin & Personal Protective Equipment Donations\"},\"description\":{\"en\":\"As a step of concern for medical personnel who are handling the Covid-19 pandemic, the Company in 2020 donated multivitamin products to several Covid-19 referral hospitals\",\"id\":\"As a step of concern for medical personnel who are handling the Covid-19 pandemic, the Company in 2020 donated multivitamin products to several Covid-19 referral hospitals\"},\"cta_text\":{\"en\":\"See Detail\"},\"cta_url\":\"https:\\/\\/linknet.co.id\\/news\\/donasi-multivitamin-alat-pelindung-diri\"},{\"logo\":\"frontend\\/src\\/assets\\/img\\/soc-logo-3.png\",\"thumbnail\":\"https:\\/\\/linknet.co.id\\/storage\\/files\\/images\\/media_activities\\/csr\\/Link-Net-Dukung-Kesehatan-dan-Pemulihan-Ekonomi-Masyarakat-Jawa-Barat.jpg\",\"title\":{\"en\":\"Link Net Supports West Java Community Health and Economic Recovery\",\"id\":\"Link Net Supports West Java Community Health and Economic Recovery\"},\"description\":{\"en\":\"PT Link Net Tbk with the First Media brand together with the Bandung City Communication and Information Office (Diskominfo) and the Bandung City Health Office held a Covid-19 vaccination\",\"id\":\"PT Link Net Tbk with the First Media brand together with the Bandung City Communication and Information Office (Diskominfo) and the Bandung City Health Office held a Covid-19 vaccination\"},\"cta_text\":{\"en\":\"See Detail\"},\"cta_url\":\"https:\\/\\/linknet.co.id\\/news\\/link-net-dukung-kesehatan-dan-pemulihan-ekonomi-masyarakat-jawa-barat\"}],\"show_community_section\":\"false\",\"community_text\":{\"en\":\"We also work with community organizations,\"},\"community_logos\":[{\"image\":\"frontend\\/src\\/assets\\/img\\/org-1.png\",\"alt_text\":\"Partner Organization 1\"},{\"image\":\"frontend\\/src\\/assets\\/img\\/org-2.png\",\"alt_text\":\"Partner Organization 2\"},{\"image\":\"frontend\\/src\\/assets\\/img\\/org-3.png\",\"alt_text\":\"Partner Organization 3\"},{\"image\":\"frontend\\/src\\/assets\\/img\\/org-4.png\",\"alt_text\":\"Partner Organization 4\"},{\"image\":\"frontend\\/src\\/assets\\/img\\/org-5.png\",\"alt_text\":\"Partner Organization 5\"},{\"image\":\"frontend\\/src\\/assets\\/img\\/org-6.png\",\"alt_text\":\"Partner Organization 6\"}],\"show_cta_section\":\"true\",\"cta_text\":{\"en\":\"View All CSR Program\"},\"cta_url\":\"https:\\/\\/linknet.co.id\\/news\\/category\\/csr\"}', 5, 1, '2025-10-13 23:53:11', '2025-12-19 09:27:47'),
(132, 10, 'information_list', '{\"custom_id\":null,\"custom_class\":null,\"bg_type\":\"color\",\"bg_color\":\"#ffffff\",\"bg_color_text\":\"#ffffff\",\"bg_image\":null,\"bg_position\":\"center\",\"show_intro_section\":\"false\",\"intro_label\":{\"en\":\"MEDIA & ACTIVITIES\"},\"intro_title\":{\"en\":\"Keep up with what\'s happening at Linknet\"},\"intro_description\":{\"en\":\"Stay Update\"},\"info_sections\":[{\"show_section\":\"true\",\"title\":\"Office Address\",\"title_id\":\"Alamat Kantor\",\"content\":\"<p>Centennial Tower 26th Floor, Unit D.\\u2028Jl. Jendral Gatot Subroto Kav. 24-25\\u2028Jakarta 12930, Indonesia<\\/p>\",\"content_id\":null,\"show_cta\":\"true\",\"cta_text\":\"Direction\",\"cta_link\":\"https:\\/\\/www.google.com\\/maps?vet=12ahUKEwjO17z1po-RAxWNoGMGHWr2ByMQ8UF6BAgyEAM..i&lei=na0maY6VOY3BjuMP6uyfmAI&cs=0&um=1&ie=UTF-8&fb=1&gl=id&sa=X&geocode=KYOwtDip_mkuMS0IW1fcUITg&daddr=Centennial+Tower,+Jl.+Gatot+Subroto+Jl.+Kuningan+Barat+Raya+No.Kav+24-25+26th+Floor,+Unit+D,+RT.3\\/RW.2,+Kuningan+Tim.,+Kec.+Mampang+Prpt.,+Kota+Jakarta+Selatan,+Daerah+Khusus+Ibukota+Jakarta+12930\",\"cta_icon\":\"arrow-right.svg\",\"show_related_articles\":\"false\",\"show_documents\":\"false\"},{\"show_section\":\"true\",\"title\":\"Establishment & Lines of Business\",\"title_id\":\"Pendirian & Lini Bisnis\",\"content\":\"<p>The Company was established in 1996 initially engaged in trading of goods and services. But in 2000, the Company\\u2019s line of business was changed to focus on information technology and general services.<\\/p>\",\"content_id\":\"<p>Perseroan didirikan pada tahun 1996 awalnya memiliki kegiatan usaha di bidang perdagangan barang dan jasa. Tetapi pada tahun 2000, kegiatan usaha Perseroan berubah menjadi di bidang teknologi informasi dan jasa penyelenggaraan internet serta jasa pada umumnya.<\\/p>\",\"show_cta\":\"true\",\"cta_text\":\"See Milestone\",\"cta_link\":\"\\/about\\/milestone\",\"cta_icon\":\"arrow-right.svg\",\"show_related_articles\":\"false\",\"show_documents\":\"false\"},{\"show_section\":\"true\",\"title\":\"Public Accountant\",\"title_id\":\"Akuntan Publik\",\"content\":\"<p><strong>KAP Rintis, Jumadi, Rianto &amp; Rekan (PwC Indonesia)<\\/strong><br>World Trade Center (WTC 3), Jalan Jend. Sudirman Kav. 29-31, Kel. Karet, Kec. Setiabudi, Jakarta Selatan<\\/p>\",\"content_id\":null,\"show_cta\":\"false\",\"cta_text\":\"Learn More\",\"cta_link\":null,\"cta_icon\":\"arrow-right.svg\",\"show_related_articles\":\"false\",\"show_documents\":\"false\"},{\"show_section\":\"true\",\"title\":\"Stock Administration Bureau\",\"title_id\":\"Biro Administrasi Saham\",\"content\":\"<p>PT Sharestar Indonesia<br>SOPO Del Office Towers &amp; Lifestyle, Tower B Lantai 18\\u2028Jl. Mega Kuningan Barat III, Lot 10. 1-6 Kawasan Mega Kuningan<\\/p>\",\"content_id\":null,\"show_cta\":\"false\",\"cta_text\":\"Learn More\",\"cta_link\":null,\"cta_icon\":\"arrow-right.svg\",\"show_related_articles\":\"false\",\"show_documents\":\"false\"},{\"show_section\":\"true\",\"title\":\"Share Ownership\",\"title_id\":\"Kepemilikan Saham\",\"content\":\"<p>Based on the Shareholders Register as of 31 December 2025: AXIATA INVESTMENTS (INDONESIA) SDN. BHD. holds 69.38% of the shares; PT XL AXIATA Tbk holds 19.22% of the shares; Public holds 7.5%of the shares; and Treasury Shares holds 3.9% of the shares.<\\/p>\",\"content_id\":\"<p>Berdasarkan Daftar Pemegang Saham per 31 Desember 2025: AXIATA INVESTMENTS (INDONESIA) SDN. BHD. memegang 69,38% saham; PT XL AXIATA Tbk memegang 19,22% saham; Publik memegang 7,5% saham; dan Saham Perbendaharaan memegang 3,9% saham.<\\/p>\",\"show_cta\":\"false\",\"cta_text\":\"Learn More\",\"cta_link\":null,\"cta_icon\":\"arrow-right.svg\",\"show_related_articles\":\"false\",\"show_documents\":\"false\"}]}', 2, 1, '2025-10-14 00:49:00', '2026-01-27 06:59:17'),
