(168, 25, 'hero_section', '{\"title\": \"Let\'s Discover the Possibilities Together!\", \"custom_id\": \"lnSection__hero\", \"pill_text\": \"Life at Linknet\", \"aria_label\": \"Our Vision\", \"button_icon\": \"arrow-top-right.svg\", \"button_link\": \"#\", \"button_size\": \"btn-lg\", \"button_text\": \"Get to Know Us\", \"description\": \"We believe in your potential. This is the right time for you to step up your skills and discover endless possibilities.\", \"button_style\": \"btn-secondary-outline-reverse\", \"custom_class\": \"lnSection__hero\", \"pill_visible\": true, \"button_visible\": true, \"parallax_value\": \"0.25\", \"parallax_effect\": true, \"background_image\": \"src/assets/bg/top-view-business-people-writing-mind-map-while-brainstorm-idea-convocation.jpg\", \"description_width\": \"w-75\"}', 1, 1, '2025-10-14 23:01:54', '2025-10-14 23:01:59'),
(169, 25, 'card_with_highlight_summary', '{\"cards\": [{\"icon\": \"src/assets/icons/pdf-circlesvg.svg\", \"title\": \"Annual Reports\", \"button_link\": \"#\", \"button_text\": \"View More\", \"description\": \"Temukan perjalanan pertumbuhan, strategi, dan pencapaian kami setiap tahunnya.\"}, {\"icon\": \"src/assets/icons/pdf-circlesvg.svg\", \"title\": \"Financial Statement\", \"button_link\": \"#\", \"button_text\": \"View More\", \"description\": \"Lihat transparansi keuangan kami yang mendorong kepercayaan dan peluang baru.\"}, {\"icon\": \"src/assets/icons/pdf-circlesvg.svg\", \"title\": \"Sustainable Reports\", \"button_link\": \"#\", \"button_text\": \"View More\", \"description\": \"Ikuti komitmen kami membangun masa depan berkelanjutan bagi bisnis dan masyarakat.\"}], \"custom_id\": \"\", \"bg_section\": \"\", \"intro_label\": \"SUSTAINABILITY REPORTS & POLICY\", \"intro_title\": \"Transparency & Accountability\", \"custom_class\": \"lnSection__reports\", \"highlight_year\": \"2024\", \"highlight_title\": \"Highlight Report Summary\", \"highlight_metrics\": [{\"delta\": \"(+14.65% YoY)\", \"label\": \"Homes Connected (Open Access)\", \"value\": \"4.07M\"}, {\"delta\": \"(–7.21%)\", \"label\": \"GHG Emissions (Lower is Better)\", \"value\": \"32,421.94 ton CO₂e\"}, {\"delta\": \"(+4.91%)\", \"label\": \"% Women in Workforce\", \"value\": \"29.07%\"}], \"intro_description\": \"Explore our latest Sustainability Reports, ESG policies, and alignment with international frameworks to ensure responsible growth.\", \"show_cards_section\": true, \"show_intro_section\": true, \"highlight_thumbnail\": \"src/assets/img/LINK AR2024 Rev_page-0001.jpg\", \"highlight_button_link\": \"#\", \"highlight_button_text\": \"Download Report\", \"show_highlight_section\": true}', 2, 1, '2025-10-14 23:01:59', '2025-10-14 23:01:59'),
