(176, 29, 'contact_us', '{\"email\": \"corporate.secretary@linknet.co.id\", \"phone\": \"021-29536800\", \"title\": \"We\'re Here to Help\", \"address\": \"Centennial Tower Lantai 26, Unit D. Jl. Jenderal Gatot Subroto Kav. 24-25 Jakarta 12930, Indonesia\", \"title_id\": \"Kami Siap Membantu Anda\", \"custom_id\": \"\", \"address_id\": \"Centennial Tower Lantai 26, Unit D. Jl. Jenderal Gatot Subroto Kav. 24-25 Jakarta 12930, Indonesia\", \"description\": \"We\'re here to assist you with any questions, concerns, or feedback you may have. Connect with us today!\", \"custom_class\": \"\", \"description_id\": \"Kami siap membantu Anda dengan pertanyaan, keluhan, atau masukan yang Anda miliki. Hubungi kami hari ini!\"}', 1, 1, '2025-10-19 00:05:16', '2025-10-19 00:05:17'),
