(234, 50, 'accordion', '{\"custom_id\":\"\",\"custom_class\":\"\",\"show_intro\":true,\"intro_label\":{\"en\":\"FAQ\",\"id\":\"Pertanyaan Umum\"},\"intro_title\":{\"en\":\"Frequently Asked Questions\",\"id\":\"Pertanyaan yang Sering Diajukan\"},\"intro_description\":{\"en\":\"Find answers to common questions\",\"id\":\"Temukan jawaban untuk pertanyaan umum\"},\"items\":[{\"title\":{\"en\":\"What is this service?\",\"id\":\"Apa itu layanan ini?\"},\"content\":{\"en\":\"This is a description of the service and what it provides to users.\",\"id\":\"Ini adalah deskripsi layanan dan apa yang diberikan kepada pengguna.\"},\"expanded\":true},{\"title\":{\"en\":\"How do I get started?\",\"id\":\"Bagaimana cara memulai?\"},\"content\":{\"en\":\"To get started, simply follow these steps and you\'ll be up and running in no time.\",\"id\":\"Untuk memulai, cukup ikuti langkah-langkah ini dan Anda akan siap dalam waktu singkat.\"},\"expanded\":false},{\"title\":{\"en\":\"What are the requirements?\",\"id\":\"Apa saja persyaratannya?\"},\"content\":{\"en\":\"Here are the main requirements you need to meet before using this service.\",\"id\":\"Berikut adalah persyaratan utama yang perlu Anda penuhi sebelum menggunakan layanan ini.\"},\"expanded\":false}],\"style\":\"default\",\"allow_multiple\":false,\"bg_type\":\"color\",\"bg_color\":\"#ffffff\",\"bg_image\":\"\",\"bg_position\":\"center\"}', 1, 1, '2025-12-10 08:10:14', '2025-12-10 08:10:14'),
